// Node 2 — Scan the read-only vault and emit one item per Markdown file.
// Uses Node's fs/path, enabled via NODE_FUNCTION_ALLOW_BUILTIN=fs,path.
const fs = require('fs');
const path = require('path');

const ROOT = '/data/vault';
const SKIP_DIRS = new Set(['.git', '.obsidian', '.trash', 'node_modules', '.stfolder']);
const out = [];

function walk(dir) {
  let entries;
  try {
    entries = fs.readdirSync(dir, { withFileTypes: true });
  } catch (e) {
    return; // unreadable dir -> skip silently
  }
  for (const entry of entries) {
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) {
      if (SKIP_DIRS.has(entry.name)) continue;
      walk(full);
    } else if (entry.isFile() && entry.name.toLowerCase().endsWith('.md')) {
      try {
        out.push({ json: { file: path.relative(ROOT, full), raw: fs.readFileSync(full, 'utf8') } });
      } catch (e) { /* skip unreadable file */ }
    }
  }
}

walk(ROOT);

if (out.length === 0) {
  throw new Error('No Markdown files under /data/vault. Check VAULT_PATH in .env and that the drive is shared in Docker Desktop > Settings > Resources > File Sharing.');
}
return out;

// Node 3 — Parse frontmatter, apply optional WhatsApp action-log overrides,
// collect STALE projects AND due learning reviews, rank, build the LLM request.
// Returns [] when there is nothing to send, so nodes 4 & 5 never run.
const items = $input.all();
const GLOBAL_STALE_DAYS = 5;
const GLOBAL_REVIEW_DAYS = 7;
const ACTIONS_FILE = '/data/inbox/.actions.jsonl';

const now = new Date();
const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
const z = (n) => String(n).padStart(2, '0');
const ymd = (d) => `${d.getFullYear()}-${z(d.getMonth() + 1)}-${z(d.getDate())}`;

let actions = [];
try {
  const fs = require('fs');
  if (fs.existsSync(ACTIONS_FILE)) {
    actions = fs.readFileSync(ACTIONS_FILE, 'utf8')
      .split(/\r?\n/).filter(Boolean)
      .map((l) => { try { return JSON.parse(l); } catch (e) { return null; } })
      .filter((a) => a && a.project && a.ts && a.action);
  }
} catch (e) { /* no inbox -> ignore overrides */ }

function latestAction(title) {
  const t = String(title).toLowerCase().trim();
  let best = null;
  for (const a of actions) {
    const p = String(a.project).toLowerCase().trim();
    if (!p) continue;
    if (t.includes(p) || p.includes(t)) {
      if (!best || new Date(a.ts) > new Date(best.ts)) best = a;
    }
  }
  return best;
}

function parseLocalDate(s) {
  const m = String(s).trim().match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (!m) return null;
  return new Date(Number(m[1]), Number(m[2]) - 1, Number(m[3]));
}
const daysBetween = (a, b) => Math.round((a - b) / 86400000);

function parseFrontmatter(text) {
  const m = text.match(/^﻿?---\s*\r?\n([\s\S]*?)\r?\n---/);
  if (!m) return {};
  const fm = {};
  for (const line of m[1].split(/\r?\n/)) {
    const t = line.trim();
    if (!t || t.startsWith('#')) continue;
    const idx = line.indexOf(':');
    if (idx === -1) continue;
    const key = line.slice(0, idx).trim();
    let val = line.slice(idx + 1).trim();
    val = val.replace(/\s+#.*$/, '');
    val = val.replace(/^["']|["']$/g, '');
    if (val.startsWith('[') && val.endsWith(']')) {
      val = val.slice(1, -1).split(',').map((s) => s.trim().replace(/^["']|["']$/g, '')).filter(Boolean);
    }
    fm[key] = val;
  }
  return fm;
}

function bodyOf(text) {
  const m = text.match(/^﻿?---\s*\r?\n[\s\S]*?\r?\n---\s*\r?\n?/);
  return m ? text.slice(m[0].length) : text;
}

function effectiveDate(title, fmDate) {
  let last = parseLocalDate(fmDate);
  const act = latestAction(title);
  if (act) {
    const a = String(act.action).toLowerCase();
    if (a === 'done') return { removed: true, last };
    if (a === 'touch') {
      const ad = parseLocalDate(String(act.ts).slice(0, 10));
      if (ad && last && ad > last) last = ad;
    }
    // 'reopen' un-excludes without resetting the clock.
  }
  return { removed: false, last };
}

const stale = [];
const reviews = [];
for (const item of items) {
  const text = item.json.raw;
  if (typeof text !== 'string') continue;
  const fm = parseFrontmatter(text);
  const type = String(fm.type || '').toLowerCase();
  const status = String(fm.status || '').toLowerCase();
  if (status === 'done') continue;
  const fallbackTitle = String(item.json.file || 'untitled').replace(/\.md$/i, '').split('/').pop();

  if (type === 'project') {
    const title = fm.title || fallbackTitle;
    const { removed, last } = effectiveDate(title, fm.last_actionable_date);
    if (removed || !last) continue;
    const threshold = parseInt(fm.stale_after_days, 10) || GLOBAL_STALE_DAYS;
    const daysStale = daysBetween(today, last);
    if (daysStale < threshold) continue;
    const recent = bodyOf(text).split(/\r?\n/).map((l) => l.trim())
      .filter((l) => l && !/^#{1,6}\s/.test(l) && /^- |^\* |^\d+\.|\[ \]|\bnext\b|\blog\b|\d{4}-\d{2}-\d{2}/i.test(l))
      .slice(-8).join('\n');
    stale.push({ title, status, priority: String(fm.priority || 'medium').toLowerCase(),
      deadline: fm.deadline || '', last_actionable_date: ymd(last), days_stale: daysStale, recent_notes: recent });
  } else if (type === 'learning') {
    const topic = fm.title || fallbackTitle;
    const { removed, last } = effectiveDate(topic, fm.last_actionable_date);
    if (removed || !last) continue;
    const interval = parseInt(fm.review_interval_days, 10) || GLOBAL_REVIEW_DAYS;
    const daysSince = daysBetween(today, last);
    if (daysSince < interval) continue;
    reviews.push({ topic, days_since: daysSince, confidence: fm.confidence || '' });
  }
}

if (stale.length === 0 && reviews.length === 0) return [];

const prRank = { high: 0, medium: 1, low: 2 };
stale.sort((a, b) => {
  const ad = a.deadline ? parseLocalDate(a.deadline) : null;
  const bd = b.deadline ? parseLocalDate(b.deadline) : null;
  if (ad && bd && +ad !== +bd) return ad - bd;
  if (ad && !bd) return -1;
  if (!ad && bd) return 1;
  const pr = (prRank[a.priority] ?? 1) - (prRank[b.priority] ?? 1);
  if (pr !== 0) return pr;
  return b.days_stale - a.days_stale;
});
reviews.sort((a, b) => (b.days_since - a.days_since) || ((parseFloat(a.confidence) || 1) - (parseFloat(b.confidence) || 1)));

const SYSTEM_PROMPT = `You are the user's Agentic Second Brain - a terse, perceptive chief-of-staff that resurfaces neglected work each morning over WhatsApp.
You receive JSON with today's date, a PRE-SORTED array stale_projects (most important first), and a due_reviews array of learning notes due for spaced recall. Either array may be empty.

RULES:
1. If stale_projects is non-empty, centre the message on the FIRST project. If it is empty but due_reviews is non-empty, centre the message on the first review instead.
2. Output ONLY the WhatsApp message body. No preamble, no sign-off, no markdown code fences, no JSON.
3. Format for a narrow phone screen with WhatsApp syntax: *bold* (single asterisks), _italics_, leading emojis as bullets. Keep it under ~90 words. Short lines. One blank line between blocks.
4. When nudging a project, use this EXACT 3-step flow, each label on its own line:
   🧊 *HOOK* - what went cold and for how many days (use days_stale).
   🧠 *CONTEXT* - paraphrase recent_notes so they recognise where they left off.
   ✅ *MICRO-ACTION* - ONE concrete task doable in 10 minutes. Absurdly low-friction.
5. If due_reviews is non-empty, add ONE final line: 📚 *REVIEW* - name one topic from due_reviews and suggest a 2-minute active-recall prompt.
6. Tone: warm, direct, zero guilt-tripping. Never invent facts not present in the notes. If recent_notes is empty, say the thread went quiet and make the micro-action "re-read the note".`;
const user = JSON.stringify({ today: ymd(today), stale_projects: stale, due_reviews: reviews }, null, 2);
return [{ json: { system: SYSTEM_PROMPT, user, count: stale.length + reviews.length } }];

// Node 4b — Normalize the cloud LLM reply into a clean WhatsApp body.
// Accepts the Groq/OpenAI shape (choices[0].message.content) OR the Gemini
// shape (candidates[0].content.parts[].text), unwraps stray \`\`\` code fences,
// and fails LOUD on an empty reply so the error-handler alerts you instead of
// Evolution rejecting a blank message (HTTP 400) or a garbage nudge going out.
const res = $input.first().json || {};

let text = '';
if (res.choices && res.choices[0] && res.choices[0].message) {
  text = res.choices[0].message.content || '';
} else if (res.candidates && res.candidates[0] && res.candidates[0].content) {
  text = (res.candidates[0].content.parts || []).map((p) => (p && p.text) || '').join('');
} else if (typeof res.content === 'string') {
  text = res.content;
}

text = String(text).trim();
const fence = text.match(/^```[a-zA-Z]*\r?\n?([\s\S]*?)\r?\n?```$/);
if (fence) text = fence[1].trim();

if (!text) {
  const reason = (res.error && res.error.message)
    || (res.choices && res.choices[0] && res.choices[0].finish_reason)
    || (res.candidates && res.candidates[0] && res.candidates[0].finishReason)
    || 'empty response';
  throw new Error('Cloud LLM returned no usable text (' + reason + '). Nothing sent to WhatsApp.');
}

// Safety net: WhatsApp accepts long text, but never let a runaway model blast
// a wall of text to the phone. The nudge is designed to be ~90 words.
if (text.length > 4000) text = text.slice(0, 3990) + '\n…';

return [{ json: { text } }];
